# sexp.py
# a library for handling (simplified) s-expressions
# doesn't bother with parsing data, but does bother with string delimiters

# main interface:
# read_all(string) -> list-based s-expressions
# write(s-exp list) -> string
# Symbol class to hold symbols (as opposed to strings)
# plist_find(p-list, key) -> elt (ignores first element)

__all__ = ('read_all', 'write', 'Symbol', 'plist_find',)

_Raise = object()

cdef class StringStream :
    cdef bytes str
    cdef int i
    def __init__(self, str) :
        self.str = str
        self.i = 0
    def read(self) :
        if self.i == len(self.str) :
            return ''
        else :
            self.i += 1
            return self.str[self.i-1]
    def peek(self) :
        if self.i == len(self.str) :
            return ''
        else :
            return self.str[self.i]

cdef class Symbol :
    cdef bytes s
    def __init__(self, s) :
        self.s = s
    def __richcmp__(Symbol self, Symbol s2, t) :
        if t == 2:
            return type(self) == type(s2) and self.s == s2.s
        elif t == 3:
            return type(self) != type(s2) or self.s != s2.s
        else:
            raise NotImplementedError("Invalid comparison: %s" % t)
    def __str__(self) :
        return self.s
    def __repr__(self) :
        return "<Symbol: %s>" % self.s

def plist_find(plist, key, default=_Raise) :
    cdef int i
    for i in range(0, len(plist), 2) :
        if str(plist[i]) == str(key) :
            return plist[i+1]
    if default is _Raise:
        return KeyError("Could not find %r" % key)
    else:
        return default

def read_all(bytes str) :
    cdef StringStream stream
    stream = StringStream(str)
    ret = []
    while(stream.peek() != '') :
        r = read(stream)
        if r != None :
            ret.append(r)
    return ret

def read(StringStream stream) :
    sexp_eat_spaces(stream)
    if stream.peek() == '(' :
        stream.read()
        sexp_eat_spaces(stream)
        ret = []
        while stream.peek() != ')' :
            if stream.peek() == '' :
                raise Exception("Not enough closing paretheses")
            ret.append(read(stream))
            sexp_eat_spaces(stream)
        stream.read()
        return ret
    else :
        if stream.peek() == '"' :
            return sexp_read_string(stream)
        else :
            r = sexp_read_symbol(stream)
            try :
                return int(r)
            except ValueError :
                try :
                    return float(r)
                except ValueError :
                    return Symbol(r)

def sexp_read_string(stream) :
    stream.read()
    s = ""
    while True :
        if stream.peek() == '\\' :
            stream.read()
            e = stream.read()
            s += ("\\"+e).decode("string_escape")
        elif stream.peek() == '"' :
            stream.read()
            return s
        elif stream.peek() == '' :
            raise Exception("sexp_read_string: no closing quote")
        else :
            s += stream.read()

def sexp_read_symbol(stream) :
    r = stream.read()
    while not (sexp_is_whitespace(stream.peek())
               or stream.peek() == '('
               or stream.peek() == ')'
               or stream.peek() == '') :
        r += stream.read()
    return r

def one_of(thing, things) :
    for t in things :
        if thing == t :
            return True
    return False

def sexp_is_whitespace(a) :
    return one_of(a, [' ','\t','\n','\r','\f','\v'])

def sexp_eat_spaces(stream) :
    while(sexp_is_whitespace(stream.peek())) :
        stream.read()

def write(exp) :
    if isinstance(exp, list) :
        return "("+(" ".join([write(x) for x in exp]))+")"
    elif isinstance(exp, Symbol) :
        return str(exp)
    elif isinstance(exp, str) :
        return "\""+exp.encode("string_escape")+"\""
    else :
        return str(exp)

import pickle
import threading


cdef _thread_local = threading.local()
cdef _contexts = {}


cdef class _OptimizationConfig:

    def __init__(
            self, optimize_impl, *,
            int max_trials=100,
            float timeout=1,
            float expected_total_time_per_trial=100 * 1e-6,
            float max_total_time_per_trial=0.1):
        self.optimize_impl = optimize_impl
        self.max_trials = max_trials
        self.timeout = timeout
        self.expected_total_time_per_trial = expected_total_time_per_trial
        self.max_total_time_per_trial = max_total_time_per_trial


cdef class _OptimizationContext:

    def __init__(self, str key, _OptimizationConfig config):
        self.key = key
        self.config = config
        self._params_map = {}
        self._dirty = False

    def get_params(self, key):
        return self._params_map.get(key)

    def set_params(self, key, params):
        self._params_map[key] = params
        self._dirty = True

    def save(self, filepath):
        with open(filepath, mode='wb') as f:
            pickle.dump((self.key, self._params_map), f)
        self._dirty = False

    def load(self, filepath):
        with open(filepath, mode='rb') as f:
            key, params_map = pickle.load(f)
        if key != self.key:
            raise ValueError(
                'Optimization key mismatch {} != {}'.format(key, self.key))
        self._params_map = params_map
        self._dirty = False

    def _is_dirty(self):
        return self._dirty


cpdef _OptimizationContext get_current_context():
    try:
        return _thread_local.current_context
    except AttributeError:
        return None


def set_current_context(_OptimizationContext context):
    _thread_local.current_context = context


def get_new_context(
        str key, object optimize_impl, dict config_dict):
    c = _contexts.get(key)
    if c is None:
        config = _OptimizationConfig(optimize_impl, **config_dict)
        c = _OptimizationContext(key, config)
        _contexts[key] = c
    return c


def _clear_all_contexts_cache():
    global _contexts
    assert get_current_context() is None
    _contexts = {}
